SELECT ?winner ?winnerLabel WHERE {
  ?event wdt:P31 wd:Q468893 ;
         wdt:P585 ?date ;
         wdt:P36 ?winner .
  ?winner rdfs:label ?winnerLabel .
  FILTER(LANG(?eventLabel) = 'en') .
  FILTER(REGEX(STR(?eventLabel), 'American League Championship Series', 'i')) .
  FILTER(YEAR(?date) = 2017) .
  FILTER(LANG(?winnerLabel) = 'en')
} LIMIT 1

